// WidgetCacheConfig parameterizes an attached read-through cache view.
type WidgetCacheConfig struct {
	// Capacity is the L1 capacity in entries, not bytes — budget
	// memory as Capacity × the largest expected entity payload. Zero
	// or negative selects the default (1024).
	Capacity int
	// FetchCriteria are the cache's batch-flush thresholds.
	FetchCriteria caching.FetchCriteria
	// FreshnessTTL enables age-based staleness onset (ADR-0100's
	// external-writer staleness story): entries older than this read
	// as stale — strict reads miss and queue a refetch, accept-stale
	// reads keep serving. Zero disables (staleness stays signal-only).
	FreshnessTTL time.Duration
	// NegativeTTL enables absent-key marking: keys a clean fetch did
	// not return are treated as absent for this long — misses on them
	// neither queue nor suspend work items, so replay loops over keys
	// that do not exist terminate. Zero disables.
	NegativeTTL time.Duration
}

// WidgetCache is the batched read-through, write-through KV view over a
// WidgetStore (ADR-0100 SD5): misses queue under work items and flush
// as one IN (…) lookup, and local writes populate the view at Commit —
// pinned until the store's Flush makes them durable — so reads after
// writes hit immediately. Admission is version-gated on the entity's
// Order timestamp: a raced refetch of an older row bounces off. Only
// EXTERNAL writers can leave the view stale; they need a caller-
// provided signal: MarkStale / Invalidate / InvalidateAll (a freshness
// TTL option exists on the underlying cache). Raw() commits and
// discarded writes invalidate instead of populating. Like the store
// it wraps, a view is single-goroutine. W is the work-item type (use
// struct{} when the suspend/replay machinery is not needed).
type WidgetCache[W comparable] struct {
	st    *WidgetStore
	cfg   WidgetCacheConfig
	cache *caching.ReadThroughCache[uint64, *WidgetEntity, W]
}

// NewWidgetCache attaches a read-through, write-through cache view to st,
// registering its write-through and flush hooks with the store. Views
// attach for the store's lifetime — there is no detach.
func NewWidgetCache[W comparable](st *WidgetStore, cfg WidgetCacheConfig) (inst *WidgetCache[W]) {
	if cfg.Capacity <= 0 {
		cfg.Capacity = 1024
	}
	inst = &WidgetCache[W]{st: st, cfg: cfg}
	inst.rebuild()
	// The hooks close over the view, not the cache instance, keeping
	// them correct if the cache is ever swapped out.
	st.onWrite = append(st.onWrite, func(k uint64, ent *WidgetEntity) {
		if ent == nil {
			inst.cache.Delete(k) // not materializable or discarded: invalidate
			return
		}
		inst.cache.AddItem(k, ent) // version-gated write-through
		inst.cache.Pin(k)          // dirty-window latch, released by Flush
	})
	st.onFlush = append(st.onFlush, func(k uint64) { inst.cache.Unpin(k) })
	return
}

func (inst *WidgetCache[W]) rebuild() {
	opts := []caching.CacheOption[uint64, *WidgetEntity, W]{
		// Admission mirrors the table's newest-row-per-key semantics:
		// the Order timestamp is the entity's monotonic version.
		caching.WithVersioning[uint64, *WidgetEntity, W](func(e *WidgetEntity) int64 { return e.Ts.UnixNano() }),
	}
	if inst.cfg.FreshnessTTL > 0 {
		opts = append(opts, caching.WithFreshnessTTL[uint64, *WidgetEntity, W](inst.cfg.FreshnessTTL))
	}
	if inst.cfg.NegativeTTL > 0 {
		opts = append(opts, caching.WithNegativeCaching[uint64, *WidgetEntity, W](inst.cfg.NegativeTTL))
	}
	inst.cache = caching.NewReadThroughCache[uint64, *WidgetEntity, W](inst.cfg.Capacity, &widgetFetcher{st: inst.st}, inst.cfg.FetchCriteria, opts...)
}

// Get retrieves an entity by Key through the cache; local writes are
// visible immediately (write-through). A miss queues the key for the
// next batch fetch (the caching suspend/replay contract). A miss can
// also mean the batched fetch errored (misses swallow fetch errors;
// the circuit breaker backs off) — GetFetch surfaces the error
// instead, and the store's Latest stays the authoritative check. The
// returned entity is shared with the cache: treat it as immutable.
func (inst *WidgetCache[W]) Get(key uint64) (ent *WidgetEntity, found bool) {
	return inst.cache.Get(key)
}

// GetFetch is the single-lookup read: the cached entity when present,
// otherwise one immediate batched point fetch — fetch errors surface
// instead of reading as misses, so found=false with err=nil is the
// authoritative absent. The fetched row is cached unless the key is
// in the dirty write window. Prefer Get plus the work-item protocol
// when batching lookups across a frame; the initial miss here also
// queues the key, so a later batch fetch may include it redundantly
// (harmless).
func (inst *WidgetCache[W]) GetFetch(ctx context.Context, key uint64) (ent *WidgetEntity, found bool, err error) {
	ent, found = inst.cache.Get(key)
	if found {
		return
	}
	ents, err := inst.st.queryEntities(ctx, inst.st.fetchLatestSQL([]uint64{key}))
	if err != nil {
		err = eh.Errorf("get-fetch: %w", err)
		return
	}
	for _, e := range ents {
		if e.ID != key {
			continue
		}
		ent = e
		found = true
		if _, d := inst.st.dirty[key]; !d {
			inst.cache.AddItem(key, e)
		}
	}
	return
}

// WorkItem marks the current work item for the cache's miss bookkeeping.
func (inst *WidgetCache[W]) WorkItem(w W) iter.Seq[functional.NilIteratorValueType] {
	return inst.cache.WorkItem(w)
}

// IterateReadyWorkItems flushes the queued keys when the fetch criteria
// are met and replays the work items that had misses.
func (inst *WidgetCache[W]) IterateReadyWorkItems(ctx context.Context) iter.Seq[W] {
	return inst.cache.IterateReadyWorkItems(ctx)
}

// IterateRestWorkItems forces a fetch of all queued keys and replays
// the pending work items.
func (inst *WidgetCache[W]) IterateRestWorkItems(ctx context.Context) iter.Seq[W] {
	return inst.cache.IterateRestWorkItems(ctx)
}

// AdvanceEpoch advances the cache's pinning epoch — call once per
// frame / batch so untouched L1 entries become evictable.
func (inst *WidgetCache[W]) AdvanceEpoch() {
	inst.cache.AdvanceEpoch()
}

// MarkStale flags the key's cached entry as stale — the external-writer
// signal: the next strict read misses and queues a refetch, while
// accept-stale reads keep serving the old value until it lands.
func (inst *WidgetCache[W]) MarkStale(key uint64) {
	inst.cache.MarkAsStale(key)
}

// MarkStaleIfOlder is the version-carrying external-writer signal:
// it stales the cached entry only if its Order is below order, so a
// redundant signal for a version the view already holds is free —
// the natural sink for an invalidation stream carrying (key, Order).
func (inst *WidgetCache[W]) MarkStaleIfOlder(key uint64, order time.Time) {
	inst.cache.MarkAsStaleIfOlder(key, order.UnixNano())
}

// Invalidate drops the key's cached entry (L1 and stash).
func (inst *WidgetCache[W]) Invalidate(key uint64) {
	inst.cache.Delete(key)
}

// InvalidateAll drops every cached entry — the bulk external-writer
// signal (e.g. after an import). In-flight miss bookkeeping (queued
// keys, pending work items) and the dirty-window pins are dropped
// with it: call between frames, with no suspended work and no
// unflushed local writes (the fetcher's dirty-guard keeps pre-write
// rows out of the cleared cache until the next Flush, at the cost of
// misses on those keys).
func (inst *WidgetCache[W]) InvalidateAll() {
	inst.cache.Clear()
}

// GetLive is the cached state-view read: the cache's newest row for
// the key with the tombstone read as absent — exact under this
// process's single writer (local writes invalidate); external writers
// need MarkStale / Invalidate. The store's uncached GetLive stays
// the authoritative read. A miss queues the batch fetch like Get.
func (inst *WidgetCache[W]) GetLive(key uint64) (ent *WidgetEntity, found bool) {
	ent, found = inst.cache.Get(key)
	if found && ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// GetLiveAcceptStale is the stale-while-revalidate state-view read:
// a stale entry is served immediately (stale=true) while the refetch
// queues in the background — pair with the work-item replay loop.
// Tombstones read as absent; stale then reports whether that verdict
// came from a stale entry.
func (inst *WidgetCache[W]) GetLiveAcceptStale(key uint64) (ent *WidgetEntity, found bool, stale bool) {
	ent, found, stale = inst.cache.GetAcceptStale(key)
	if found && ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// fetchLatestSQL is the batched newest-row-per-key point lookup shared
// by the cache fetcher and GetFetch.
func (inst *WidgetStore) fetchLatestSQL(keys []uint64) string {
	var sb strings.Builder
	sb.WriteString("SELECT * FROM ")
	sb.WriteString(WidgetTableName)
	sb.WriteString(" WHERE " + WidgetColKey + " IN (")
	for i, k := range keys {
		if i > 0 {
			sb.WriteByte(',')
		}
		sb.WriteString(widgetKeyLiteral(k))
	}
	sb.WriteString(") ORDER BY " + WidgetColOrder + " DESC LIMIT 1 BY " + WidgetColKey)
	sb.WriteString(widgetArrowOutputSettings)
	return sb.String()
}

// widgetFetcher implements caching.ItemFetcherI for attached cache views —
// an unexported shim so the fetch plumbing stays off the store's
// public method set.
type widgetFetcher struct{ st *WidgetStore }

var _ caching.ItemFetcherI[uint64, *WidgetEntity] = (*widgetFetcher)(nil)

// DeterminePartition implements caching.ItemFetcherI. Single partition
// in v1 (one table, one server).
func (inst *widgetFetcher) DeterminePartition(key uint64) uint64 { return 0 }

// FetchItemSinglePartition implements caching.ItemFetcherI: one batched
// point lookup per fetch. Duplicate versions collapse newest-first.
// Dirty keys (written locally, not yet flushed) are fetched but not
// cached. With write-through the version gate already rejects the
// pre-write row while the newer entry is resident; this guard is the
// remaining defense for dirty keys the views could NOT materialize
// (Raw commits, discarded writes) and for InvalidateAll inside a
// dirty window, where the cache is cold and the gate has nothing to
// compare against.
func (inst *widgetFetcher) FetchItemSinglePartition(ctx context.Context, partition uint64, keys []uint64, target caching.ItemTargetI[uint64, *WidgetEntity]) (err error) {
	ents, err := inst.st.queryEntities(ctx, inst.st.fetchLatestSQL(keys))
	if err != nil {
		return
	}
	for _, ent := range ents {
		if _, d := inst.st.dirty[ent.ID]; d {
			continue
		}
		target.AddItem(ent.ID, ent)
	}
	return
}

// Baked ADR-0066 Filter artefacts: rows carrying a conforming
// component. Generated from Plan ⋈ IR; membership ids are literals.
const ()

// Latest returns the newest row for key, tombstone-blind (the raw
// row-level primitive — a deleted key still returns its tombstone
// row; GetLive is the interpreted state-view read). Reads see only
// flushed rows.
func (inst *WidgetStore) Latest(ctx context.Context, key uint64) (ent *WidgetEntity, found bool, err error) {
	sql := "SELECT * FROM " + WidgetTableName +
		" WHERE " + WidgetColKey + " = " + widgetKeyLiteral(key) +
		" ORDER BY " + WidgetColOrder + " DESC LIMIT 1" + widgetArrowOutputSettings
	ents, err := inst.queryEntities(ctx, sql)
	if err != nil || len(ents) == 0 {
		return
	}
	ent = ents[0]
	found = true
	return
}

// Replay iterates the rows for key with the order column >= fromOrder
// in ascending order — the event-replay primitive. A zero fromOrder
// replays everything (zero time.Time has no defined UnixNano;
// recordstore.SeqTs(0) is the equivalent explicit bound);
// opts.To bounds the replay exclusively ("state as of To") and
// opts.Limit caps the row count. The sequence is single-use; ctx
// must stay valid until iteration completes; the query may execute
// at call time or lazily during iteration (buffered in v1 — a
// streaming executor changes nothing visible); an error ends the
// sequence as a final (nil, err) pair. Reads see only flushed rows.
func (inst *WidgetStore) Replay(ctx context.Context, key uint64, fromOrder time.Time, opts recordstore.ReplayOpts) iter.Seq2[*WidgetEntity, error] {
	sql := "SELECT * FROM " + WidgetTableName +
		" WHERE " + WidgetColKey + " = " + widgetKeyLiteral(key)
	if !fromOrder.IsZero() {
		sql += " AND " + WidgetColOrder + " >= fromUnixTimestamp64Nano(" + strconv.FormatInt(fromOrder.UnixNano(), 10) + ")"
	}
	if !opts.To.IsZero() {
		sql += " AND " + WidgetColOrder + " < fromUnixTimestamp64Nano(" + strconv.FormatInt(opts.To.UnixNano(), 10) + ")"
	}
	sql += " ORDER BY " + WidgetColOrder + " ASC"
	if opts.Limit > 0 {
		sql += " LIMIT " + strconv.Itoa(opts.Limit)
	}
	sql += widgetArrowOutputSettings
	return inst.iterateEntities(ctx, sql)
}

// --- state view (Delete / GetLive; ADR-0100 SD4). Versioned writes
// go through Begin — appending a new version IS the update. ---

// Delete appends a tombstone row for id (no components; lifecycle marks
// the deletion). The tombstone writes through to attached cache views
// like any commit — a versioned deletion, so GetLive reads the key as
// absent immediately.
func (inst *WidgetStore) Delete(id uint64, ts time.Time) (err error) {
	var env WidgetEnvelope // a tombstone carries no pass-through payload
	inst.dml.BeginEntity().SetId(id, env.Alt).SetTimestamp(ts).SetRouting(env.Region, env.Tags).SetLifecycle(recordstore.LifecycleTombstone)
	err = inst.dml.CommitEntity()
	if err != nil {
		_ = inst.dml.RollbackEntity() // discard the failed frame; the store stays usable
		return
	}
	inst.buffered++
	inst.dirty[id] = struct{}{}
	inst.notifyWrite(id, &WidgetEntity{ID: id, Ts: ts, Lifecycle: recordstore.LifecycleTombstone})
	return
}

// GetLive is Latest plus tombstone interpretation: newest row wins, a
// tombstone reads as absent — the state-view read (the cache view
// carries the cached twin).
func (inst *WidgetStore) GetLive(ctx context.Context, key uint64) (ent *WidgetEntity, found bool, err error) {
	ent, found, err = inst.Latest(ctx, key)
	if err != nil || !found {
		return
	}
	if ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// --- decode (Arrow → entity bags). ---

// widgetSectionReaderI is the uniform slice of the generated read-access
// readers. Column indices stay at their constructor defaults — the
// schema order a SELECT * returns.
type widgetSectionReaderI interface {
	LoadFromRecord(raruntime.RecordI) error
	Release()
}

func (inst *WidgetStore) queryEntities(ctx context.Context, sql string) (ents []*WidgetEntity, err error) {
	for rec, rerr := range inst.exec.QueryArrow(ctx, sql) {
		if rerr != nil {
			err = eh.Errorf("query entities: %w", rerr)
			return
		}
		batch, derr := decodeWidgetRecord(rec)
		rec.Release()
		if derr != nil {
			err = derr
			return
		}
		ents = append(ents, batch...)
	}
	return
}

// iterateEntities adapts the buffered query path to the single-use
// iterator contract shared by Replay and the Scan verbs: entities
// yield in query order; an error yields once as (nil, err) and ends
// the sequence.
func (inst *WidgetStore) iterateEntities(ctx context.Context, sql string) iter.Seq2[*WidgetEntity, error] {
	return func(yield func(*WidgetEntity, error) bool) {
		ents, err := inst.queryEntities(ctx, sql)
		if err != nil {
			yield(nil, err)
			return
		}
		for _, ent := range ents {
			if !yield(ent, nil) {
				return
			}
		}
	}
}

// decodeWidgetRecord reads one fetched Arrow record into entity bags:
// envelope from the plain readers, components via presence-gated,
// membership-matched reads (fat rows carry optional components — the
// kind-homogeneous helpers cannot decode them).
func decodeWidgetRecord(rec arrow.RecordBatch) (ents []*WidgetEntity, err error) {
	idR := lowlevel.NewReadAccessWidgetTablePlainEntityIdAttributes()
	tsR := lowlevel.NewReadAccessWidgetTablePlainEntityTimestampAttributes()
	rtR := lowlevel.NewReadAccessWidgetTablePlainEntityRoutingAttributes()
	lcR := lowlevel.NewReadAccessWidgetTablePlainEntityLifecycleAttributes()
	readers := []widgetSectionReaderI{idR, tsR, rtR, lcR}
	for _, r := range readers {
		err = r.LoadFromRecord(rec)
		if err != nil {
			err = eh.Errorf("load widget reader from record: %w", err)
			return
		}
	}
	defer func() {
		for _, r := range readers {
			r.Release()
		}
	}()

	n := idR.ValueId.Len()
	tsType, ok := tsR.ValueTs.DataType().(*arrow.TimestampType)
	if !ok {
		err = eh.Errorf("order column is not a timestamp (got %s)", tsR.ValueTs.DataType())
		return
	}
	ents = make([]*WidgetEntity, 0, n)
	for i := range n {
		ent := &WidgetEntity{
			ID:        idR.ValueId.Value(i),
			Ts:        tsR.ValueTs.Value(i).ToTime(tsType.Unit).UTC(),
			Lifecycle: lcR.ValueLifecycle.Value(i),
		}
		ent.Alt = idR.GetAttrValueAlt(raruntime.EntityIdx(i))
		ent.Region = rtR.GetAttrValueRegion(raruntime.EntityIdx(i))
		ent.Tags = slices.Collect(rtR.GetAttrValueTags(raruntime.EntityIdx(i)))
		ents = append(ents, ent)
	}
	return
}
